const root = $input.first().json;

const candidates = [
  ['entries', root.entries],
  ['data', root.data],
  ['agreements', root.agreements],
  ['items', root.items],
  ['results', root.results],
  ['root', Array.isArray(root) ? root : null],
].filter(([, value]) => Array.isArray(value));

const [arrayKey, agreements] = candidates[0] ?? ['none', []];
const sample = agreements.slice(0, 3);
const sampleFields = [...new Set(sample.flatMap((agreement) => Object.keys(agreement ?? {})))].sort();
const first = agreements[0] ?? {};
const relationshipId = first.id ?? first.relationshipId ?? first.relationship_id ?? first.agreementId ?? first.agreement_id ?? null;

return [
  {
    json: {
      totalCount: root.totalCount ?? root.total_count ?? null,
      detectedArrayKey: arrayKey,
      agreementCount: agreements.length,
      sampleFields,
      sample,
      relationshipId,
    },
  },
];

const detail = $input.first().json;
const serviceArrays = [];

function walk(value, path = []) {
  if (Array.isArray(value)) {
    if (path.some((part) => String(part).toLowerCase().includes('service'))) {
      serviceArrays.push({ path: path.join('.'), count: value.length, sample: value.slice(0, 2) });
    }
    value.forEach((child, index) => walk(child, [...path, index]));
    return;
  }
  if (!value || typeof value !== 'object') return;
  for (const [key, child] of Object.entries(value)) {
    walk(child, [...path, key]);
  }
}

walk(detail);

return [
  {
    json: {
      rootFields: Object.keys(detail ?? {}).sort(),
      relationshipId: detail.id ?? detail.relationshipId ?? detail.relationship_id ?? detail.agreementId ?? detail.agreement_id ?? null,
      agreementName: detail.name ?? detail.agreementName ?? detail.agreement_name ?? null,
      status: detail.status ?? null,
      serviceArrays,
      rawSample: detail,
    },
  },
];
